#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(param);

my $cgi = new CGI;
my $log_dir = '/path/to/log/directory';  # Set your log directory here

my $filename = param('logfile');
if ($filename !~ m/^[a-zA-Z0-9_-]+$/) {
    die "Invalid filename";
}

open(my $fh, '<', "$log_dir/$filename") or die "Could not open file '$filename' $!";

print "Content-type: text/plain\n\n";

while (my $line = <$fh>) {
    print $line;
}

close($fh);